use std::collections::HashSet;

fn distinct_weights_count(weights: &[i32]) -> i32 {
    let mut distinct_weights = HashSet::new();
    distinct_weights.insert(0); // We can always measure zero weight

    fn dfs(weights: &[i32], current_weight: i32, distinct_weights: &mut HashSet<i32>) {
        if weights.is_empty() {
            return;
