fn count_ways_to_climb(stairs: i32) -> i32 {
    if stairs <= 0 {
        return 0;
    } else if stairs == 1 {
        return 1;
    }

    let mut dp = vec![0; (stairs + 1) as usize];
    dp[0] = 1;
    dp[1] = 1;

    for i in 2..=stairs {
