fn count_paths(n: usize, m: usize, horse_x: usize, horse_y: usize) -> usize {
    // Define the control points of the horse
    let horse_control_points = vec![
        (horse_x, horse_y),
        (horse_x + 2, horse_y + 1),
        (horse_x + 2, horse_y - 1),
        (horse_x - 2, horse_y + 1),
        (horse_x - 2, horse_y - 1),
        (horse_x + 1, horse_y + 2),
        (horse_x + 1, horse_y - 2),
        (horse_x - 1, horse_y + 2),
        (horse_x - 1, horse_y - 2),
