fn count_passing_ways(n: i32, m: i32) -> i32 {
    if n <= 2 || m <= 0 {
        return 0;
    }

    let n = n as usize;
    let m = m as usize;

    // Create a 2D vector to store the number of ways to pass the ball
    let mut dp = vec![vec![0; m + 1]; n];

    // Base case: Initially, the ball is with the first student
    dp[0][0] = 1;

    // Fill the dp table
    for j in 1..=m {
        for i in 0..n {
            dp[i][j] = dp[(i + n - 1) % n][j - 1] + dp[(i + 1) % n][j - 1];
        }
    }

    // The result is the number of ways to pass the ball back to the first student after m passes
    dp[0][m]
}

